<?php namespace App\Models; use Illuminate\Database\Eloquent\Model; use Illuminate\Database\Eloquent\SoftDeletes; class PaymentRecord extends Model{use SoftDeletes;protected $fillable=['payment_number','order_id','customer_id','billing_document_id','provider','provider_reference','status','currency','amount','idempotency_key','requested_by_id','captured_by_id','refunded_by_id','authorized_at','captured_at','refunded_at','failed_at','failure_reason','metadata'];protected function casts():array{return ['amount'=>'decimal:2','authorized_at'=>'datetime','captured_at'=>'datetime','refunded_at'=>'datetime','failed_at'=>'datetime','metadata'=>'array'];}public function order(){return $this->belongsTo(Order::class);}public function customer(){return $this->belongsTo(User::class,'customer_id');}public function billingDocument(){return $this->belongsTo(BillingDocument::class);}public function events(){return $this->hasMany(PaymentEvent::class)->orderByDesc('created_at');}}
